## Latency Histogram
```python
from dataclasses import dataclass, field

@dataclass
class Histogram:
    buckets: list[float]
    counts: list[int] = field(default_factory=list)

    def __post_init__(self) -> None:
        if not self.counts:
            self.counts = [0] * len(self.buckets)

    def observe(self, value: float) -> None:
        for i, upper in enumerate(self.buckets):
            if value <= upper:
                self.counts[i] += 1
                return
        self.counts[-1] += 1

    def percentile(self, p: float) -> float:
        total = sum(self.counts)
        if total == 0:
            return 0.0
        target = total * p
        running = 0
        for upper, count in zip(self.buckets, self.counts):
            running += count
            if running >= target:
                return upper
        return self.buckets[-1]
```

## OAuth State Manager
```python
import secrets
import time
from dataclasses import dataclass

@dataclass
class StateEntry:
    value: str
    expires_at: float

class OAuthStateStore:
    def __init__(self, ttl_seconds: float = 300.0) -> None:
        self.ttl = ttl_seconds
        self._states: dict[str, StateEntry] = {}

    def issue(self) -> str:
        self._purge()
        value = secrets.token_urlsafe(24)
        self._states[value] = StateEntry(value=value, expires_at=time.time() + self.ttl)
        return value

    def consume(self, value: str) -> bool:
        self._purge()
        entry = self._states.pop(value, None)
        return entry is not None

    def _purge(self) -> None:
        now = time.time()
        expired = [k for k, v in self._states.items() if v.expires_at <= now]
        for key in expired:
            del self._states[key]
```

## Image Resize Planner
