from dataclasses import dataclass

@dataclass
class Size:
    width: int
    height: int

def plan_resize(src: Size, max_width: int, max_height: int) -> Size:
    ratio = min(max_width / src.width, max_height / src.height, 1.0)
    return Size(int(src.width * ratio), int(src.height * ratio))
